  1→import { type RecordId, type Surreal } from "surrealdb";
  2→import type { ObservationSummary, OnboardingState } from "../../shared/contracts";
  3→import {
  4→  listConversationEntities,
  5→  listWorkspaceOpenQuestions,
  6→  listWorkspaceProjectSummaries,
  7→  listWorkspaceRecentDecisions,
  8→  type ConversationEntity,
  9→  type WorkspaceDecisionSummary,
 10→  type WorkspaceProjectSummary,
 11→  type WorkspaceQuestionSummary,
 12→} from "../graph/queries";
 13→import { listWorkspaceOpenObservations } from "../observation/queries";
 14→import { loadOnboardingSummary } from "../onboarding/onboarding-state";
 15→import { chatComponentSystemPrompt } from "./chat-component-system-prompt";
 16→
 17→export type ChatContext = {
 18→  conversationEntities: ConversationEntity[];
 19→  workspaceSummary: {
 20→    projects: WorkspaceProjectSummary[];
 21→    recentDecisions: WorkspaceDecisionSummary[];
 22→    openQuestions: WorkspaceQuestionSummary[];
 23→    openObservations: ObservationSummary[];
 24→  };
 25→  onboardingSummary?: string;
 26→};
 27→
 28→type ChatContextLoaders = {
 29→  listConversationEntities: typeof listConversationEntities;
 30→  listWorkspaceProjectSummaries: typeof listWorkspaceProjectSummaries;
 31→  listWorkspaceRecentDecisions: typeof listWorkspaceRecentDecisions;
 32→  listWorkspaceOpenQuestions: typeof listWorkspaceOpenQuestions;
 33→  listWorkspaceOpenObservations: typeof listWorkspaceOpenObservations;
 34→  loadOnboardingSummary: typeof loadOnboardingSummary;
 35→};
 36→
 37→export async function buildChatContext(input: {
 38→  surreal: Surreal;
 39→  conversationRecord: RecordId<"conversation", string>;
 40→  workspaceRecord: RecordId<"workspace", string>;
 41→  loaders?: ChatContextLoaders;
 42→  inheritedEntityIds?: RecordId[];
 43→}): Promise<ChatContext> {
 44→  const loaders = input.loaders ?? {
 45→    listConversationEntities,
 46→    listWorkspaceProjectSummaries,
 47→    listWorkspaceRecentDecisions,
 48→    listWorkspaceOpenQuestions,
 49→    listWorkspaceOpenObservations,
 50→    loadOnboardingSummary,
 51→  };
 52→
 53→  const [conversationEntities, projects, recentDecisions, openQuestions, openObservations, onboardingSummary] = await Promise.all([
 54→    loaders.listConversationEntities({
 55→      surreal: input.surreal,
 56→      conversationRecord: input.conversationRecord,
 57→      workspaceRecord: input.workspaceRecord,
 58→      limit: 60,
 59→      ...(input.inheritedEntityIds && input.inheritedEntityIds.length > 0
 60→        ? { inheritedEntityIds: input.inheritedEntityIds }
 61→        : {}),
 62→    }),
 63→    loaders.listWorkspaceProjectSummaries({
 64→      surreal: input.surreal,
 65→      workspaceRecord: input.workspaceRecord,
 66→      limit: 20,
 67→    }),
 68→    loaders.listWorkspaceRecentDecisions({
 69→      surreal: input.surreal,
 70→      workspaceRecord: input.workspaceRecord,
 71→      limit: 12,
 72→    }),
 73→    loaders.listWorkspaceOpenQuestions({
 74→      surreal: input.surreal,
 75→      workspaceRecord: input.workspaceRecord,
 76→      limit: 12,
 77→    }),
 78→    loaders.listWorkspaceOpenObservations({
 79→      surreal: input.surreal,
 80→      workspaceRecord: input.workspaceRecord,
 81→      limit: 10,
 82→    }),
 83→    loaders.loadOnboardingSummary(input.surreal, input.workspaceRecord),
 84→  ]);
 85→
 86→  return {
 87→    conversationEntities,
 88→    workspaceSummary: {
 89→      projects,
 90→      recentDecisions,
 91→      openQuestions,
 92→      openObservations,
 93→    },
 94→    onboardingSummary,
 95→  };
 96→}
 97→
 98→function formatConversationEntities(entities: ConversationEntity[]): string {
 99→  if (entities.length === 0) {
100→    return "- none";
101→  }
102→
103→  return entities
104→    .slice(0, 20)
105→    .map((entity) => `- ${entity.kind}: ${entity.name} (confidence ${entity.confidence.toFixed(2)})`)
106→    .join("\n");
107→}
108→
109→function formatProjectList(projects: WorkspaceProjectSummary[]): string {
110→  if (projects.length === 0) {
111→    return "- none";
112→  }
113→
114→  return projects
115→    .slice(0, 15)
116→    .map((project) => `- ${project.name} [id: ${project.id}] active tasks: ${project.activeTaskCount}`)
117→    .join("\n");
118→}
119→
120→function formatDecisionList(decisions: WorkspaceDecisionSummary[]): string {
121→  if (decisions.length === 0) {
122→    return "- none";
123→  }
124→
125→  return decisions
126→    .slice(0, 15)
127→    .map((decision) => {
128→      const project = decision.project ? ` project: ${decision.project}` : "";
129→      return `- ${decision.name} [id: ${decision.id}] status: ${decision.status}${project}`;
130→    })
131→    .join("\n");
132→}
133→
134→function formatQuestionList(questions: WorkspaceQuestionSummary[]): string {
135→  if (questions.length === 0) {
136→    return "- none";
137→  }
138→
139→  return questions
140→    .slice(0, 15)
141→    .map((question) => {
142→      const project = question.project ? ` project: ${question.project}` : "";
143→      return `- ${question.name} [id: ${question.id}]${project}`;
144→    })
145→    .join("\n");
146→}
147→
148→function formatObservationList(observations: ObservationSummary[]): string {
149→  if (observations.length === 0) {
150→    return "- none";
151→  }
152→
153→  return observations
154→    .slice(0, 10)
155→    .map((observation) => {
156→      const category = observation.category ? `, ${observation.category}` : "";
157→      return `- [${observation.severity}] ${observation.text} (by ${observation.sourceAgent}, ${observation.status}${category})`;
158→    })
159→    .join("\n");
160→}
