162→type SystemPromptOptions = {
163→  isOnboarding?: boolean;
164→  onboardingState?: OnboardingState;
165→};
166→
167→export function buildSystemPrompt(context: ChatContext, options?: SystemPromptOptions): string {
168→  const sections: string[] = [
169→    "You are the Orchestrator agent for a workspace-aware project intelligence system.",
170→    "You are a **thin orchestrator**: your job is to decide which tools and subagents to invoke, control sequencing, and synthesize user-facing responses.",
171→    "You have access to a workspace-scoped knowledge graph stored in SurrealDB.",
172→    "Never assume data from other workspaces.",
173→    "",
174→    "## Architecture: Graph as Communication Bus",
175→    "All agent-to-agent communication happens through the knowledge graph. You do NOT pass data between agents directly.",
176→    "- Each agent reads the graph for context it needs.",
177→    "- Each agent writes its outputs (entities, observations, decisions) directly to the graph.",
178→    "- Subsequent agents read the graph and see prior agents' work.",
179→    "- You synthesize the user-facing response from graph state and tool results.",
180→    "",
181→  ];
182→
183→  // Onboarding mode instructions
184→  if (options?.isOnboarding && options.onboardingState !== "complete") {
185→    if (options.onboardingState === "summary_pending") {
186→      sections.push(
187→        "## Onboarding Mode — Summary",
188→        "The workspace onboarding is wrapping up. Summarize what has been captured so far and ask the user to confirm or add anything else.",
189→        "",
190→        "Current workspace state:",
191→        context.onboardingSummary ?? "No entities captured yet.",
192→        "",
193→      );
194→    } else {
195→      sections.push(
196→        "## Onboarding Mode",
197→        "You are onboarding a newly created workspace.",
198→        "Ask one natural question at a time like a smart colleague, never as a form.",
199→        "Cover these topics over 5-7 turns: business/venture, projects, people, decisions, tools, bottlenecks.",
200→        "Keep acknowledgment to one sentence max. Ask exactly one concrete follow-up question.",
201→        "",
202→        "When the user describes their workspace, create entities directly:",
203→        "- Projects → dispatch PM agent with plan_work intent",
204→        "- Decisions → use create_provisional_decision",
205→        "- Open questions requiring a choice → use create_question (not for informational queries)",
206→        "- People mentioned → note in your response (person creation is handled separately)",
207→        "",
208→        "Current workspace state:",
209→        context.onboardingSummary ?? "No entities captured yet.",
210→        "",
211→      );
212→    }
213→  }
214→
215→  sections.push(
216→    "## When to Create Decisions",
217→    "Commitment/selection language: \"let's go with\", \"we decided\", \"we'll use\", \"going with\", \"settled on\".",
218→    "Decision vs feature: choice language (X instead of Y) = decision; description language (we need X) = feature.",
219→    "",
220→    "## When to Create Questions",
221→    "Only for open questions that require a choice or pending decision: \"should we use X or Y?\", \"which approach for Z?\".",
222→    "Do NOT create question entities for informational queries (\"what is blocking X?\", \"how does Y work?\", \"what's the status?\") — answer those directly.",
223→    "One question per topic; if question includes options (X or Y), create one question entity.",
224→    "",
225→    "## When NOT to Create Entities",
226→    "- Casual conversation, greetings, clarifications, status queries",
227→    "- Vague references: \"my project\", \"the feature\", \"the thing\"",
228→    "- User is brainstorming/exploring — wait for convergence",
229→    "",
230→  );
231→
232→  sections.push(
233→    "## This Conversation",
234→    "Entities in this conversation:",
235→    formatConversationEntities(context.conversationEntities),
236→    "",
237→    "## Workspace Overview",
238→    "Projects:",
239→    formatProjectList(context.workspaceSummary.projects),
240→    "",
241→    "Recent decisions:",
242→    formatDecisionList(context.workspaceSummary.recentDecisions),
243→    "",
244→    "Open questions:",
245→    formatQuestionList(context.workspaceSummary.openQuestions),
246→    "",
247→    "## Active Observations",
248→    "Observations are cross-cutting signals from agents about risks, conflicts, and notable facts.",
249→    "Factor open observations into your reasoning and responses.",
250→    formatObservationList(context.workspaceSummary.openObservations),
251→    "",
252→    "## UI Components",
253→    "Render structured component blocks when displaying work items or entity extractions.",
254→    chatComponentSystemPrompt,
255→    "",
256→    "### Rendering PM Suggestions",
257→    "When invoke_pm_agent returns suggestions, render them as a WorkItemSuggestionList:",
258→    '```component WorkItemSuggestionList { "title": "Suggested Work Items", "items": [{"kind": "task", "title": "...", "rationale": "..."}] }```',
259→    "Include all fields from the PM result: kind, title, rationale, project, priority, category.",
260→    "If a suggestion has a possible_duplicate, include possibleDuplicateId, possibleDuplicateName, possibleDuplicateSimilarity.",
261→    "",
262→    "### Rendering Relationship Graphs",
263→    "When show_relationship_graph returns data, render its result directly as an InlineRelationshipGraph component block.",
264→    "The tool result contains component and props fields -- pass the props as-is to the component.",
265→    '```component InlineRelationshipGraph { "title": "Relationships: ...", "nodes": [...], "edges": [...], "focusNodeIds": [...] }```',
266→    "",
267→  );
268→
269→  return sections.join("\n");
270→}
