205→      text: assistantText,
206→      ...(assistantSuggestions.length > 0 ? { suggestions: assistantSuggestions } : {}),
207→      createdAt: now,
208→    });
209→
210→    await input.deps.surreal.update(conversationRecord).merge({
211→      updatedAt: now,
212→    });
213→
214→    void persistEmbeddings({
215→      surreal: input.deps.surreal,
216→      embeddingModel: input.deps.embeddingModel,
217→      embeddingDimension: input.deps.config.embeddingDimension,
218→      assistantMessageRecord,
219→      assistantText,
220→      entities: embeddingTargets,
