      messages: assistantContextRows.map((row) => ({
        role: row.role,
        text: row.text,
      })),
      onToken: async (token) => {
        input.deps.sse.emitEvent(input.messageId, {
          type: "token",
          messageId: input.messageId,
          token,
        });
      },
    });

    let assistantText = graphAwareResponse.text.trim();
    persistedEntities.push(...graphAwareResponse.collectedEntities);
    persistedRelationships.push(...graphAwareResponse.collectedRelationships);

    const unresolvedAssigneeSuggestions = [...unresolvedAssigneeNames].map(
      (name) => `You mentioned ${name} - want to add them to workspace people?`,
    );
    const assistantSuggestions = sanitizeAssistantSuggestions(unresolvedAssigneeSuggestions, 3);

    // Post-response hooks (entities now created during orchestrator execution)
    await refreshConversationTouchedBy(input.deps.surreal, conversationRecord);
    await maybeUpgradeConversationTitle(input.deps.surreal, conversationRecord);

    if (assistantText.trim().length === 0) {
      assistantText = "I could not generate a response for that request.";
    }

    const assistantMessageRecord = new RecordId("message", input.messageId);
    await input.deps.surreal.create(assistantMessageRecord).content({
      conversation: conversationRecord,
      role: "assistant",
      text: assistantText,
      ...(assistantSuggestions.length > 0 ? { suggestions: assistantSuggestions } : {}),
      createdAt: now,
    });

    await input.deps.surreal.update(conversationRecord).merge({
      updatedAt: now,
    });

    void persistEmbeddings({
      surreal: input.deps.surreal,
      embeddingModel: input.deps.embeddingModel,
      embeddingDimension: input.deps.config.embeddingDimension,
      assistantMessageRecord,
      assistantText,
      entities: embeddingTargets,
    }).catch(() => undefined);

    input.deps.sse.emitEvent(input.messageId, {
      type: "extraction",
      messageId: input.messageId,
      entities: persistedEntities,
      relationships: persistedRelationships,
    });

    if (onboardingBefore !== onboardingAfter) {
      input.deps.sse.emitEvent(input.messageId, {
        type: "onboarding_state",
        messageId: input.messageId,
        onboardingState: onboardingAfter,
      });
    }

    input.deps.sse.emitEvent(input.messageId, {
      type: "assistant_message",
      messageId: input.messageId,
      text: assistantText,
      ...(assistantSuggestions.length > 0 ? { suggestions: assistantSuggestions } : {}),
    });

    input.deps.sse.emitEvent(input.messageId, {
      type: "done",
      messageId: input.messageId,
    });

    logInfo("chat.message.process.execution.completed", "Chat message processing execution completed", {
      conversationId: input.conversationId,
      messageId: input.messageId,
      workspaceId: input.workspaceRecord.id as string,
      entityCount: persistedEntities.length,
      relationshipCount: persistedRelationships.length,
      durationMs: elapsedMs(startedAt),
    });
  } catch (error) {
    logError("chat.message.process.execution.failed", "Chat message processing execution failed", error, {
      conversationId: input.conversationId,
      messageId: input.messageId,
      workspaceId: input.workspaceRecord.id as string,
      durationMs: elapsedMs(startedAt),
    });
    const errorText = userFacingError(error, "chat processing failed");
    input.deps.sse.emitEvent(input.messageId, {
      type: "error",
      messageId: input.messageId,
      error: errorText,
    });
  }
}

function sanitizeAssistantSuggestions(suggestions: string[], limit: number): string[] {
  return [...new Set(suggestions.map((value) => value.trim()))]
    .filter((value) => value.length > 0 && value.length <= 140)
    .slice(0, limit);
}

import { RecordId } from "surrealdb";
import type { ExtractedEntity, ExtractedRelationship, OnboardingAction } from "../../shared/contracts";
import { loadAssistantConversationContext } from "../extraction/context-loaders";
import { loadBranchChain, loadMessagesWithInheritance } from "./branch-chain";
import { ingestAttachment } from "../extraction/document-ingestion";
import { persistEmbeddings } from "../extraction/embedding-writeback";
import { appendExtractedTools } from "../extraction/persist-extraction";
import type { ConversationRow, GraphEntityRecord, IncomingAttachment, WorkspaceRow } from "../extraction/types";
import { elapsedMs, logError, logInfo, userFacingError } from "../http/observability";
import { transitionOnboardingState } from "../onboarding/onboarding-state";
import type { ServerDependencies } from "../runtime/types";
import { runChatAgent } from "./handler";
import { getWorkspaceOwnerRecord } from "../graph/queries";
import { refreshConversationTouchedBy, maybeUpgradeConversationTitle } from "../workspace/conversation-sidebar";
import { loadWorkspaceProjects } from "../workspace/workspace-scope";

export async function processChatMessage(input: {
  deps: ServerDependencies;
  conversationId: string;
  messageId: string;
  workspaceRecord: RecordId<"workspace", string>;
  userMessageRecord: RecordId<"message", string>;
  userText: string;
  attachment?: IncomingAttachment;
  onboardingAction?: OnboardingAction;
}): Promise<void> {
  const startedAt = performance.now();
  logInfo("chat.message.process.execution.started", "Chat message processing execution started", {
    conversationId: input.conversationId,
    messageId: input.messageId,
    workspaceId: input.workspaceRecord.id as string,
    hasAttachment: input.attachment !== undefined,
  });

  try {
    const now = new Date();
    const conversationRecord = new RecordId("conversation", input.conversationId);
    const workspace = await input.deps.surreal.select<WorkspaceRow>(input.workspaceRecord);
    if (!workspace) {
      throw new Error("workspace not found");
    }

    const conversation = await input.deps.surreal.select<ConversationRow>(conversationRecord);
    if (!conversation) {
      throw new Error("conversation not found");
    }

    // Check if this conversation is a branch and load inherited context
    const branchChain = await loadBranchChain(input.deps.surreal, input.conversationId);
    const isBranch = branchChain.length > 0;

    let inheritedEntityIds: RecordId[] | undefined;
    let assistantContextRows: Array<{ id: RecordId<"message", string>; role: "user" | "assistant"; text: string; createdAt: Date | string }>;

    if (isBranch) {
      // For branches, load full message history including inherited messages
      const allMessages = await loadMessagesWithInheritance(input.deps.surreal, input.conversationId, 30);
      assistantContextRows = allMessages
        .map((m) => ({
          id: new RecordId("message", m.id),
          role: m.role,
          text: m.text,
          createdAt: m.createdAt,
        }))
        .slice(-10);

      // Derive inherited entity IDs from extraction_relations on inherited messages
      const inheritedMsgIds = allMessages
        .filter((m) => m.inherited)
        .map((m) => new RecordId("message", m.id));

      if (inheritedMsgIds.length > 0) {
        const [entityRows] = await input.deps.surreal
          .query<[Array<{ out: RecordId }>]>(
            "SELECT DISTINCT out FROM extraction_relation WHERE `in` IN $msgIds LIMIT 30;",
            { msgIds: inheritedMsgIds },
          )
          .collect<[Array<{ out: RecordId }>]>();
        inheritedEntityIds = entityRows.map((r) => r.out);
      }
    } else {
      assistantContextRows = await loadAssistantConversationContext(input.deps.surreal, input.conversationId);
    }

    const workspaceProjects = await loadWorkspaceProjects(input.deps.surreal, input.workspaceRecord);
    const workspaceProjectNames = workspaceProjects.map((project) => project.name);
    const persistedEntities: ExtractedEntity[] = [];
    const persistedRelationships: ExtractedRelationship[] = [];
    const embeddingTargets: Array<{ record: GraphEntityRecord; text: string }> = [];
    const extractedTools: string[] = [];
    const unresolvedAssigneeNames = new Set<string>();

    // Attachment extraction stays automatic — document ingestion is intentional
    if (input.attachment) {
      const ingestion = await ingestAttachment({
        surreal: input.deps.surreal,
        extractionModel: input.deps.extractionModel,
        embeddingModel: input.deps.embeddingModel,
        embeddingDimension: input.deps.config.embeddingDimension,
        extractionStoreThreshold: input.deps.config.extractionStoreThreshold,
        extractionModelId: input.deps.config.extractionModelId,
        workspaceRecord: input.workspaceRecord,
        conversationRecord,
        userMessageRecord: input.userMessageRecord,
        attachment: input.attachment,
        workspaceName: workspace.name,
        projectNames: workspaceProjectNames,
        now,
        onChunkResult: (chunkResult) => {
          if (chunkResult.entities.length > 0 || chunkResult.relationships.length > 0) {
            input.deps.sse.emitEvent(input.messageId, {
              type: "extraction",
              messageId: input.messageId,
              entities: chunkResult.entities,
              relationships: chunkResult.relationships,
            });
          }
        },
      });

      persistedEntities.push(...ingestion.entities);
      persistedRelationships.push(...ingestion.relationships);
      embeddingTargets.push(...ingestion.embeddingTargets);
      extractedTools.push(...ingestion.tools);
      for (const unresolvedName of ingestion.unresolvedAssigneeNames) {
        unresolvedAssigneeNames.add(unresolvedName);
      }
    }

    if (extractedTools.length > 0) {
      await appendExtractedTools(input.deps.surreal, input.workspaceRecord, extractedTools, now);
    }

    const onboardingBefore = workspace.onboarding_complete
      ? "complete"
      : workspace.onboarding_summary_pending
        ? "summary_pending"
        : "active";

    const onboardingAfter = await transitionOnboardingState({
      surreal: input.deps.surreal,
      workspaceRecord: input.workspaceRecord,
      workspace,
      onboardingAction: input.onboardingAction,
      now,
    });

    // Always run chat agent — it handles both onboarding and post-onboarding
    const workspaceOwnerRecord = await getWorkspaceOwnerRecord({
      surreal: input.deps.surreal,
      workspaceRecord: input.workspaceRecord,
    });

    const graphAwareResponse = await runChatAgent({
      surreal: input.deps.surreal,
      model: input.deps.assistantModel,
      pmModel: input.deps.pmModel,
      embeddingModel: input.deps.embeddingModel,
      embeddingDimension: input.deps.config.embeddingDimension,
      extractionModelId: input.deps.config.extractionModelId,
      extractionModel: input.deps.extractionModel,
      extractionStoreThreshold: input.deps.config.extractionStoreThreshold,
      conversationRecord,
      workspaceRecord: input.workspaceRecord,
      currentMessageRecord: input.userMessageRecord,
      latestUserText: input.userText,
      isOnboarding: onboardingAfter !== "complete",
      onboardingState: onboardingAfter,
      ...(workspaceOwnerRecord ? { workspaceOwnerRecord } : {}),
      ...(inheritedEntityIds && inheritedEntityIds.length > 0 ? { inheritedEntityIds } : {}),
      messages: assistantContextRows.map((row) => ({
        role: row.role,
        text: row.text,
      })),
      onToken: async (token) => {
        input.deps.sse.emitEvent(input.messageId, {
          type: "token",
          messageId: input.messageId,
          token,
        });
      },
    });

    let assistantText = graphAwareResponse.text.trim();
    persistedEntities.push(...graphAwareResponse.collectedEntities);
    persistedRelationships.push(...graphAwareResponse.collectedRelationships);

    const unresolvedAssigneeSuggestions = [...unresolvedAssigneeNames].map(
      (name) => `You mentioned ${name} - want to add them to workspace people?`,
    );
    const assistantSuggestions = sanitizeAssistantSuggestions(unresolvedAssigneeSuggestions, 3);

    // Post-response hooks (entities now created during orchestrator execution)
    await refreshConversationTouchedBy(input.deps.surreal, conversationRecord);
    await maybeUpgradeConversationTitle(input.deps.surreal, conversationRecord);

    if (assistantText.trim().length === 0) {
      assistantText = "I could not generate a response for that request.";
    }

    const assistantMessageRecord = new RecordId("message", input.messageId);
    await input.deps.surreal.create(assistantMessageRecord).content({
      conversation: conversationRecord,
      role: "assistant",
      text: assistantText,
      ...(assistantSuggestions.length > 0 ? { suggestions: assistantSuggestions } : {}),
      createdAt: now,
    });

    await input.deps.surreal.update(conversationRecord).merge({
      updatedAt: now,
    });

    void persistEmbeddings({
      surreal: input.deps.surreal,
      embeddingModel: input.deps.embeddingModel,
      embeddingDimension: input.deps.config.embeddingDimension,
      assistantMessageRecord,
      assistantText,
      entities: embeddingTargets,
    }).catch(() => undefined);

    input.deps.sse.emitEvent(input.messageId, {
      type: "extraction",
      messageId: input.messageId,
      entities: persistedEntities,
      relationships: persistedRelationships,
    });

    if (onboardingBefore !== onboardingAfter) {
      input.deps.sse.emitEvent(input.messageId, {
        type: "onboarding_state",
        messageId: input.messageId,
        onboardingState: onboardingAfter,
      });
    }

    input.deps.sse.emitEvent(input.messageId, {
      type: "assistant_message",
      messageId: input.messageId,
      text: assistantText,
      ...(assistantSuggestions.length > 0 ? { suggestions: assistantSuggestions } : {}),
    });

    input.deps.sse.emitEvent(input.messageId, {
      type: "done",
      messageId: input.messageId,
    });

    logInfo("chat.message.process.execution.completed", "Chat message processing execution completed", {
      conversationId: input.conversationId,
      messageId: input.messageId,
      workspaceId: input.workspaceRecord.id as string,
      entityCount: persistedEntities.length,
      relationshipCount: persistedRelationships.length,
      durationMs: elapsedMs(startedAt),
    });
  } catch (error) {
    logError("chat.message.process.execution.failed", "Chat message processing execution failed", error, {
      conversationId: input.conversationId,
      messageId: input.messageId,
      workspaceId: input.workspaceRecord.id as string,
      durationMs: elapsedMs(startedAt),
    });
    const errorText = userFacingError(error, "chat processing failed");
    input.deps.sse.emitEvent(input.messageId, {
      type: "error",
      messageId: input.messageId,
      error: errorText,
    });
  }
}

function sanitizeAssistantSuggestions(suggestions: string[], limit: number): string[] {
  return [...new Set(suggestions.map((value) => value.trim()))]
    .filter((value) => value.length > 0 && value.length <= 140)
    .slice(0, limit);
}

import { type RecordId, type Surreal } from "surrealdb";
import type { ObservationSummary, OnboardingState } from "../../shared/contracts";
import {
  listConversationEntities,
  listWorkspaceOpenQuestions,
  listWorkspaceProjectSummaries,
  listWorkspaceRecentDecisions,
  type ConversationEntity,
  type WorkspaceDecisionSummary,
  type WorkspaceProjectSummary,
  type WorkspaceQuestionSummary,
} from "../graph/queries";
import { listWorkspaceOpenObservations } from "../observation/queries";
import { loadOnboardingSummary } from "../onboarding/onboarding-state";
import { chatComponentSystemPrompt } from "./chat-component-system-prompt";

export type ChatContext = {
  conversationEntities: ConversationEntity[];
  workspaceSummary: {
    projects: WorkspaceProjectSummary[];
    recentDecisions: WorkspaceDecisionSummary[];
    openQuestions: WorkspaceQuestionSummary[];
    openObservations: ObservationSummary[];
  };
  onboardingSummary?: string;
};

type ChatContextLoaders = {
  listConversationEntities: typeof listConversationEntities;
  listWorkspaceProjectSummaries: typeof listWorkspaceProjectSummaries;
  listWorkspaceRecentDecisions: typeof listWorkspaceRecentDecisions;
  listWorkspaceOpenQuestions: typeof listWorkspaceOpenQuestions;
  listWorkspaceOpenObservations: typeof listWorkspaceOpenObservations;
  loadOnboardingSummary: typeof loadOnboardingSummary;
};

export async function buildChatContext(input: {
  surreal: Surreal;
  conversationRecord: RecordId<"conversation", string>;
  workspaceRecord: RecordId<"workspace", string>;
  loaders?: ChatContextLoaders;
  inheritedEntityIds?: RecordId[];
}): Promise<ChatContext> {
  const loaders = input.loaders ?? {
    listConversationEntities,
    listWorkspaceProjectSummaries,
    listWorkspaceRecentDecisions,
    listWorkspaceOpenQuestions,
    listWorkspaceOpenObservations,
    loadOnboardingSummary,
  };

  const [conversationEntities, projects, recentDecisions, openQuestions, openObservations, onboardingSummary] = await Promise.all([
    loaders.listConversationEntities({
      surreal: input.surreal,
      conversationRecord: input.conversationRecord,
      workspaceRecord: input.workspaceRecord,
      limit: 60,
      ...(input.inheritedEntityIds && input.inheritedEntityIds.length > 0
        ? { inheritedEntityIds: input.inheritedEntityIds }
        : {}),
    }),
    loaders.listWorkspaceProjectSummaries({
      surreal: input.surreal,
      workspaceRecord: input.workspaceRecord,
      limit: 20,
    }),
    loaders.listWorkspaceRecentDecisions({
      surreal: input.surreal,
      workspaceRecord: input.workspaceRecord,
      limit: 12,
    }),
    loaders.listWorkspaceOpenQuestions({
      surreal: input.surreal,
      workspaceRecord: input.workspaceRecord,
      limit: 12,
    }),
    loaders.listWorkspaceOpenObservations({
      surreal: input.surreal,
      workspaceRecord: input.workspaceRecord,
      limit: 10,
    }),
    loaders.loadOnboardingSummary(input.surreal, input.workspaceRecord),
  ]);

  return {
    conversationEntities,
    workspaceSummary: {
      projects,
      recentDecisions,
      openQuestions,
      openObservations,
    },
    onboardingSummary,
  };
}

function formatConversationEntities(entities: ConversationEntity[]): string {
  if (entities.length === 0) {
    return "- none";
  }

  return entities
    .slice(0, 20)
    .map((entity) => `- ${entity.kind}: ${entity.name} (confidence ${entity.confidence.toFixed(2)})`)
    .join("\n");
}

function formatProjectList(projects: WorkspaceProjectSummary[]): string {
  if (projects.length === 0) {
    return "- none";
  }

  return projects
    .slice(0, 15)
    .map((project) => `- ${project.name} [id: ${project.id}] active tasks: ${project.activeTaskCount}`)
    .join("\n");
}

function formatDecisionList(decisions: WorkspaceDecisionSummary[]): string {
  if (decisions.length === 0) {
    return "- none";
  }

  return decisions
    .slice(0, 15)
    .map((decision) => {
      const project = decision.project ? ` project: ${decision.project}` : "";
      return `- ${decision.name} [id: ${decision.id}] status: ${decision.status}${project}`;
    })
    .join("\n");
}

function formatQuestionList(questions: WorkspaceQuestionSummary[]): string {
  if (questions.length === 0) {
    return "- none";
  }

  return questions
    .slice(0, 15)
    .map((question) => {
      const project = question.project ? ` project: ${question.project}` : "";
      return `- ${question.name} [id: ${question.id}]${project}`;
    })
    .join("\n");
}

function formatObservationList(observations: ObservationSummary[]): string {
  if (observations.length === 0) {
    return "- none";
  }

  return observations
    .slice(0, 10)
    .map((observation) => {
      const category = observation.category ? `, ${observation.category}` : "";
      return `- [${observation.severity}] ${observation.text} (by ${observation.sourceAgent}, ${observation.status}${category})`;
    })
    .join("\n");
}

type SystemPromptOptions = {
  isOnboarding?: boolean;
  onboardingState?: OnboardingState;
};

export function buildSystemPrompt(context: ChatContext, options?: SystemPromptOptions): string {
  const sections: string[] = [
    "You are the Orchestrator agent for a workspace-aware project intelligence system.",
    "You are a **thin orchestrator**: your job is to decide which tools and subagents to invoke, control sequencing, and synthesize user-facing responses.",
    "You have access to a workspace-scoped knowledge graph stored in SurrealDB.",
    "Never assume data from other workspaces.",
    "",
    "## Architecture: Graph as Communication Bus",
    "All agent-to-agent communication happens through the knowledge graph. You do NOT pass data between agents directly.",
    "- Each agent reads the graph for context it needs.",
    "- Each agent writes its outputs (entities, observations, decisions) directly to the graph.",
    "- Subsequent agents read the graph and see prior agents' work.",
    "- You synthesize the user-facing response from graph state and tool results.",
    "",
  ];

  // Onboarding mode instructions
  if (options?.isOnboarding && options.onboardingState !== "complete") {
    if (options.onboardingState === "summary_pending") {
      sections.push(
        "## Onboarding Mode — Summary",
        "The workspace onboarding is wrapping up. Summarize what has been captured so far and ask the user to confirm or add anything else.",
        "",
        "Current workspace state:",
        context.onboardingSummary ?? "No entities captured yet.",
        "",
      );
    } else {
      sections.push(
        "## Onboarding Mode",
        "You are onboarding a newly created workspace.",
        "Ask one natural question at a time like a smart colleague, never as a form.",
        "Cover these topics over 5-7 turns: business/venture, projects, people, decisions, tools, bottlenecks.",
        "Keep acknowledgment to one sentence max. Ask exactly one concrete follow-up question.",
        "",
        "When the user describes their workspace, create entities directly:",
        "- Projects → dispatch PM agent with plan_work intent",
        "- Decisions → use create_provisional_decision",
        "- Open questions requiring a choice → use create_question (not for informational queries)",
        "- People mentioned → note in your response (person creation is handled separately)",
        "",
        "Current workspace state:",
        context.onboardingSummary ?? "No entities captured yet.",
        "",
      );
    }
  }

  sections.push(
    "## When to Create Decisions",
    "Commitment/selection language: \"let's go with\", \"we decided\", \"we'll use\", \"going with\", \"settled on\".",
    "Decision vs feature: choice language (X instead of Y) = decision; description language (we need X) = feature.",
    "",
    "## When to Create Questions",
    "Only for open questions that require a choice or pending decision: \"should we use X or Y?\", \"which approach for Z?\".",
    "Do NOT create question entities for informational queries (\"what is blocking X?\", \"how does Y work?\", \"what's the status?\") — answer those directly.",
    "One question per topic; if question includes options (X or Y), create one question entity.",
    "",
    "## When NOT to Create Entities",
    "- Casual conversation, greetings, clarifications, status queries",
    "- Vague references: \"my project\", \"the feature\", \"the thing\"",
    "- User is brainstorming/exploring — wait for convergence",
    "",
  );

  sections.push(
    "## This Conversation",
    "Entities in this conversation:",
    formatConversationEntities(context.conversationEntities),
    "",
    "## Workspace Overview",
    "Projects:",
    formatProjectList(context.workspaceSummary.projects),
    "",
    "Recent decisions:",
    formatDecisionList(context.workspaceSummary.recentDecisions),
    "",
    "Open questions:",
    formatQuestionList(context.workspaceSummary.openQuestions),
    "",
    "## Active Observations",
    "Observations are cross-cutting signals from agents about risks, conflicts, and notable facts.",
    "Factor open observations into your reasoning and responses.",
    formatObservationList(context.workspaceSummary.openObservations),
    "",
    "## UI Components",
    "Render structured component blocks when displaying work items or entity extractions.",
    chatComponentSystemPrompt,
    "",
    "### Rendering PM Suggestions",
    "When invoke_pm_agent returns suggestions, render them as a WorkItemSuggestionList:",
    '```component WorkItemSuggestionList { "title": "Suggested Work Items", "items": [{"kind": "task", "title": "...", "rationale": "..."}] }```',
    "Include all fields from the PM result: kind, title, rationale, project, priority, category.",
    "If a suggestion has a possible_duplicate, include possibleDuplicateId, possibleDuplicateName, possibleDuplicateSimilarity.",
    "",
    "### Rendering Relationship Graphs",
    "When show_relationship_graph returns data, render its result directly as an InlineRelationshipGraph component block.",
    "The tool result contains component and props fields -- pass the props as-is to the component.",
    '```component InlineRelationshipGraph { "title": "Relationships: ...", "nodes": [...], "edges": [...], "focusNodeIds": [...] }```',
    "",
  );

  return sections.join("\n");
}

import { describe, expect, it } from "bun:test";
import { randomUUID } from "node:crypto";
import { RecordId, type Surreal } from "surrealdb";
import { collectSseEvents, fetchJson, setupSmokeSuite } from "./smoke-test-kit";

type ChatMessageResponse = {
  messageId: string;
  userMessageId: string;
  conversationId: string;
  workspaceId: string;
  streamUrl: string;
};

type StreamEvent =
  | { type: "assistant_message"; messageId: string; text: string }
  | {
      type: "extraction";
      messageId: string;
      entities: Array<{ id: string; kind: string; text: string; confidence: number }>;
    }
  | { type: "done"; messageId: string }
  | { type: "error"; messageId: string; error: string }
  | { type: string; messageId: string };

const getRuntime = setupSmokeSuite("pipeline");

async function createOnboardedWorkspace(
  baseUrl: string,
  surreal: Surreal,
): Promise<{ workspaceId: string; conversationId: string }> {
  const workspace = await fetchJson<{ workspaceId: string; conversationId: string }>(`${baseUrl}/api/workspaces`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      name: `Pipeline Smoke ${Date.now()}`,
      ownerDisplayName: "Marcus",
    }),
  });

  // Fast-forward onboarding so orchestrator runs in post-onboarding mode
  const workspaceRecord = new RecordId("workspace", workspace.workspaceId);
  await surreal.update(workspaceRecord).merge({
    onboarding_complete: true,
    onboarding_summary_pending: false,
    onboarding_completed_at: new Date(),
  });

  return workspace;
}

describe("agent-controlled extraction smoke", () => {
  it("orchestrator handles decision language", async () => {
