import { describe, expect, it } from "bun:test";
import { randomUUID } from "node:crypto";
import { RecordId, Surreal } from "surrealdb";
import { collectSseEvents, fetchJson, setupSmokeSuite } from "./smoke-test-kit";

type AssistantMessageEvent = {
  type: "assistant_message";
  messageId: string;
  text: string;
};

type ExtractionEvent = {
  type: "extraction";
  messageId: string;
  entities: Array<{ kind: string; text: string }>;
  relationships: Array<{ kind: string }>;
};

type StreamEvent =
  | AssistantMessageEvent
  | ExtractionEvent
  | { type: "done"; messageId: string }
  | { type: "error"; messageId: string; error: string }
  | { type: string; messageId: string };

const getRuntime = setupSmokeSuite("extraction_quality");

describe("extraction quality smoke", () => {
  it("filters placeholders and avoids unresolved person node creation", async () => {
    const { baseUrl, surreal } = getRuntime();

    const create = await fetchJson<{ workspaceId: string; conversationId: string }>(`${baseUrl}/api/workspaces`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        name: `Extraction Quality Smoke ${Date.now()}`,
        ownerDisplayName: "Marcus Stone",
      }),
    });

    const workspaceRecord = new RecordId("workspace", create.workspaceId);

    const initialPeople = await loadWorkspacePeople(surreal, workspaceRecord);
    expect(initialPeople.length).toBe(1);

    const placeholderEvents = await sendChatAndCollectEvents(baseUrl, {
      workspaceId: create.workspaceId,
      conversationId: create.conversationId,
      text: "I'll describe my project",
    });

    const placeholderExtraction = placeholderEvents.find((event) => event.type === "extraction");
    expect(placeholderExtraction).toBeDefined();
    if (!placeholderExtraction || placeholderExtraction.type !== "extraction") {
      throw new Error("Placeholder turn missing extraction event");
    }

    const hasPlaceholderProject = placeholderExtraction.entities.some(
      (entity) => entity.kind === "project" && normalizeName(entity.text) === "my project",
    );
    expect(hasPlaceholderProject).toBe(false);

    const projects = await loadWorkspaceProjects(surreal, workspaceRecord);
    const persistedPlaceholderProject = projects.some((project) => normalizeName(project.name) === "my project");
    expect(persistedPlaceholderProject).toBe(false);

    const unknownPersonEvents = await sendChatAndCollectEvents(baseUrl, {
      workspaceId: create.workspaceId,
      conversationId: create.conversationId,
      text: "Person: Sarah. Decision: Use TypeScript for backend implementation.",
    });
    expect(unknownPersonEvents.some((event) => event.type === "assistant_message")).toBe(true);

    const peopleAfterUnknown = await loadWorkspacePeople(surreal, workspaceRecord);
    const hasSarahNode = peopleAfterUnknown.some((person) => normalizeName(person.name) === "sarah");
    expect(hasSarahNode).toBe(false);
    expect(peopleAfterUnknown.length).toBe(initialPeople.length);

    const knownPersonEvents = await sendChatAndCollectEvents(baseUrl, {
      workspaceId: create.workspaceId,
      conversationId: create.conversationId,
      text: "Marcus decided to use SurrealDB for graph persistence.",
    });

    const assistantEvent = knownPersonEvents.find((event) => event.type === "assistant_message");
    expect(assistantEvent).toBeDefined();
    if (!assistantEvent || assistantEvent.type !== "assistant_message") {
      throw new Error("Known-person turn missing assistant_message");
    }

    // Orchestrator should respond meaningfully (not just silently)
    expect(assistantEvent.text.length).toBeGreaterThan(0);

    const peopleAfterKnown = await loadWorkspacePeople(surreal, workspaceRecord);
    expect(peopleAfterKnown.length).toBe(initialPeople.length);
  }, 180_000);
});

async function loadWorkspacePeople(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
): Promise<Array<{ id: RecordId<"person", string>; name: string }>> {
  const [rows] = await surreal
    .query<[Array<{ id: RecordId<"person", string>; name: string }>]>(
      "SELECT id, name FROM person WHERE id IN (SELECT VALUE `in` FROM member_of WHERE out = $workspace);",
      {
        workspace: workspaceRecord,
      },
    )
    .collect<[Array<{ id: RecordId<"person", string>; name: string }>]>();

  return rows;
}

async function loadWorkspaceProjects(
  surreal: Surreal,
  workspaceRecord: RecordId<"workspace", string>,
): Promise<Array<{ id: RecordId<"project", string>; name: string }>> {
  const [rows] = await surreal
    .query<[Array<{ id: RecordId<"project", string>; name: string }>]>(
      "SELECT id, name FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace);",
      {
        workspace: workspaceRecord,
      },
    )
    .collect<[Array<{ id: RecordId<"project", string>; name: string }>]>();

  return rows;
}

async function sendChatAndCollectEvents(
  baseUrl: string,
  input: {
    workspaceId: string;
    conversationId: string;
    text: string;
  },
): Promise<StreamEvent[]> {
  const message = await fetchJson<{ streamUrl: string }>(`${baseUrl}/api/chat/messages`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      clientMessageId: randomUUID(),
      workspaceId: input.workspaceId,
      conversationId: input.conversationId,
      text: input.text,
    }),
  });

  return await collectSseEvents<StreamEvent>(`${baseUrl}${message.streamUrl}`, 120_000);
}

function normalizeName(value: string): string {
  return value
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

import { describe, expect, it } from "bun:test";
import { randomUUID } from "node:crypto";
import { collectSseEvents, fetchJson, setupSmokeSuite } from "./smoke-test-kit";

type ChatMessageResponse = {
  messageId: string;
  userMessageId: string;
  conversationId: string;
  workspaceId: string;
  streamUrl: string;
};

type StreamEvent =
  | { type: "token"; messageId: string; token: string }
  | { type: "assistant_message"; messageId: string; text: string }
  | { type: "extraction"; messageId: string; entities: Array<{ id: string }>; relationships: Array<{ id: string }> }
  | { type: "onboarding_state"; messageId: string; onboardingState: string }
  | { type: "done"; messageId: string }
  | { type: "error"; messageId: string; error: string }
  | { type: string; messageId: string };

const getRuntime = setupSmokeSuite("onboarding");

describe("onboarding smoke", () => {
  it("bootstraps onboarding and completes full onboarding flow", async () => {
    const { baseUrl } = getRuntime();

    const create = await fetchJson<{
      workspaceId: string;
      workspaceName: string;
      conversationId: string;
      onboardingComplete: boolean;
    }>(`${baseUrl}/api/workspaces`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        name: `Smoke Workspace ${Date.now()}`,
        ownerDisplayName: "Smoke Owner",
      }),
    });

    expect(create.workspaceId.length).toBeGreaterThan(0);
    expect(create.onboardingComplete).toBe(false);

    const bootstrap = await fetchJson<{
      workspaceId: string;
      conversationId: string;
      onboardingState: string;
      messages: Array<{ role: string; text: string }>;
      seeds: Array<{ id: string }>;
    }>(`${baseUrl}/api/workspaces/${encodeURIComponent(create.workspaceId)}/bootstrap`);

    expect(bootstrap.workspaceId).toBe(create.workspaceId);
    expect(bootstrap.conversationId).toBe(create.conversationId);
    expect(bootstrap.messages.length).toBeGreaterThan(0);

    const firstChat = await fetchJson<ChatMessageResponse>(`${baseUrl}/api/chat/messages`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        clientMessageId: randomUUID(),
        workspaceId: create.workspaceId,
        conversationId: create.conversationId,
        text: "Project: Brain Platform. Decision: use TypeScript first. Question: how to handle SurrealDB scaling risk?",
      }),
    });

    const firstEvents = await collectSseEvents<StreamEvent>(`${baseUrl}${firstChat.streamUrl}`, 180_000);
    // Orchestrator handles onboarding — verify it responds to the user
    expect(firstEvents.some((event) => event.type === "assistant_message")).toBe(true);

    const uploadForm = new FormData();
    uploadForm.set("clientMessageId", randomUUID());
    uploadForm.set("workspaceId", create.workspaceId);
    uploadForm.set("conversationId", create.conversationId);
    uploadForm.set("text", "Uploading initial plan document");
    uploadForm.set(
      "file",
      new File(
        [[
          "# Product Plan\n",
          "## Current Project\n",
          "We are building Brain Platform onboarding.\n",
          "## Decision\n",
          "Choose SurrealDB with strict schemafull discipline.\n",
          "## Bottleneck\n",
          "Unclear integration sequencing across tools.\n",
        ].join("")],
        "plan.md",
        { type: "text/markdown" },
      ),
    );

    const uploadResponse = await fetchJson<ChatMessageResponse>(`${baseUrl}/api/chat/messages`, {
      method: "POST",
      body: uploadForm,
    });

    const uploadEvents = await collectSseEvents<StreamEvent>(`${baseUrl}${uploadResponse.streamUrl}`, 180_000);
    // Attachment ingestion still runs automatically — extraction event should contain document entities
    expect(uploadEvents.some((event) => event.type === "extraction")).toBe(true);

    const confirm = await fetchJson<ChatMessageResponse>(`${baseUrl}/api/chat/messages`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        clientMessageId: randomUUID(),
        workspaceId: create.workspaceId,
        conversationId: create.conversationId,
        text: "Looks good, let's go.",
        onboardingAction: "finalize_onboarding",
      }),
    });

    await collectSseEvents<StreamEvent>(`${baseUrl}${confirm.streamUrl}`, 180_000);

    const finalBootstrap = await fetchJson<{
      onboardingComplete: boolean;
      onboardingState: string;
      seeds: Array<{ sourceKind: string; sourceId: string }>;
    }>(`${baseUrl}/api/workspaces/${encodeURIComponent(create.workspaceId)}/bootstrap`);

    // Seeds are populated from extraction_relation edges — created by attachment ingestion and agent tools
    expect(finalBootstrap.seeds.length).toBeGreaterThan(0);
    // Document upload should produce document_chunk sourced seeds
    expect(finalBootstrap.seeds.some((seed) => seed.sourceKind === "document_chunk")).toBe(true);
  }, 600_000);
});

